configuration.jsScript:
const MAXTEMPERATURE = 100;
const MINTEMPERATURE = -20;

const MAXHUMIDITY = 100;
const MINHUMIDITY = 0;

const MAXPRESSURE = 1080;
const MINPRESSURE = 900;

const MAXWIND = 150;
const MINWIND = 0;

const MAXRAIN = 500;
const MINRAIN = 0;

const MAXDUST = 500;
const MINDUST = 0;

var errorList = [];

// Temperature
if ("temperature" in msg && (msg.temperature > MAXTEMPERATURE || msg.temperature < MINTEMPERATURE))
    errorList.push("wrong_temperature");

// Humidity
if ("humidity" in msg && (msg.humidity > MAXHUMIDITY || msg.humidity < MINHUMIDITY))
    errorList.push("wrong_humidity");

// Pressure
if ("pressure" in msg && (msg.pressure > MAXPRESSURE || msg.pressure < MINPRESSURE))
    errorList.push("wrong_pressure");

// Wind
if ("wind" in msg && (msg.wind > MAXWIND || msg.wind < MINWIND))
    errorList.push("wrong_wind");

// Rain
if ("rain" in msg && (msg.rain > MAXRAIN || msg.rain < MINRAIN))
    errorList.push("wrong_rain");

// Dust
if ("dust" in msg && (msg.dust > MAXDUST || msg.dust < MINDUST))
    errorList.push("wrong_dust");

// Se non ci sono errori
if (errorList.length === 0) {
    errorList.push("ok");
}

return errorList;

